import React from 'react';

import './id.css';

import icon from '../../icons/waiter.png'

export default class ID extends React.Component {

    render() {

        const contact = this.props.active;

        let img, name, age, city, email;

        if (contact.name === '') {
            img = icon;
            name = 'Имя';
            age = 'Возраст';
            city = 'Город';
            email = 'Почта';
        } else {
            img = contact.img;
            name = contact.name;
            age = contact.age;
            city = contact.city;
            email = contact.email;
        }

        return (
            <div className='id'>
                <img className='id-img' alt='img' src={img}/>
                <div className='id-info'>
                    <div className='id-text name'>{name}</div>
                    <div className='id-text age'>{age}</div>
                    <div className='id-text field'>{city}</div>
                    <div className='id-text field'>{email}</div>
                </div>
                <button onClick={() => {this.props.displayList()}} className='id-close'>Назад</button>
            </div>
        )
    }
}