import React from 'react';

import './contacts-list.css';

export default class ContactList extends React.Component {

    render() {

        let contacts = this.props.contacts;

        const list = contacts.map((contact, i) => {
            return (
                <div onClick={() => {this.props.displayID(i)}} key={i} className='contacts-list-item'>
                    <img className='contacts-list-img' src={contact.img} alt='contact'/>
                    <div>{contact.name}</div>
                </div>
            )
        })

        return (
            <div className='contacts-list'>
                {list}
            </div>
        )
    }
}