import React from 'react';

import ID from '../id/id';
import ContactList from '../contact-list/contact-list';
import SearchPanel from '../search-panel/search-panel';

import './app.css';

export default class App extends React.Component {

    constructor(props) {
        super(props);

        this.state = {
            baseContacts: [],
            contacts: [],
            active: {
                age: 0,
                city: '',
                email: '',
                img: '',
                name: '',
            },
            display: 'list',
        }

        this.displayID = this.displayID.bind(this);
        this.searchByName = this.searchByName.bind(this);
        this.displayList = this.displayList.bind(this);
    }

    async getData(url) {
        const res = await fetch(url);

        if (!res.ok) {
            console.log('Error!');
        }

        return await res.json();
    }

    async getContacts() {
        const res = await this.getData('https://randomuser.me/api/?results=10&inc=name,dob,location,email,picture');

        let contacts = res.results.map(contact => {
            return {
                name: contact.name.first + ' ' + contact.name.last,
                age: contact.dob.age,
                city: contact.location.city,
                email: contact.email,
                img: contact.picture.large,
            };
        });

        this.setState(() => {
            return {
                baseContacts: contacts.slice(),
                contacts: contacts.slice(),
                active: {
                    age: contacts[0].age,
                    city: contacts[0].city,
                    email: contacts[0].email,
                    img: contacts[0].img,
                    name: contacts[0].name,
                },
            }
        });
    }

    displayID(index) {
        let contact = this.state.contacts[index];

        this.setState(() => {
            return {
                active: {
                    age: contact.age,
                    city: contact.city,
                    email: contact.email,
                    img: contact.img,
                    name: contact.name
                },
                display: 'id'
            }
        })
    }

    displayList() {
        let list = this.state.baseContacts.slice();
        this.setState(() => {
            return {
                display: 'list',
                contacts: list,
            }
        })
    }

    searchByName(key) {
        let regex = new RegExp(`${key}`, 'i');
        let list = this.state.baseContacts.slice();

        let newList = list.filter((contact) => {
            return regex.test(contact.name);
        });

        this.setState(() => {
            return  {
                contacts: newList,
            }
        })
    }

    componentDidMount() {
        this.getContacts();
    }

    render() {

        let content;

        if (this.state.display === 'list') {
            content = <div className='app'>
                        <SearchPanel searchByName={this.searchByName}/>
                        <ContactList displayID={this.displayID} contacts={this.state.contacts}/>
                      </div>
        } else if (this.state.display === 'id') {
            content = <ID displayList={this.displayList} active={this.state.active}/>
        }

        return (
            <div>
                {content}
            </div>
        )
    }
}